// Java 26 - HTTP/3 HttpClient (JEP 517, final)
// Learn: opt a request into HTTP/3 with HttpClient.Version.HTTP_3.
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;

HttpClient client = HttpClient.newBuilder()
    // version requests HTTP/3 for this client.
    .version(HttpClient.Version.HTTP_3)
    .build();
HttpRequest request = HttpRequest.newBuilder(URI.create("https://openjdk.org/"))
    .GET()
    .build();
HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
System.out.println(response.version());
